import React, { useState } from "react";

import { useNavigate, Link } from "react-router-dom";

import { registerUser } from "../../services/authService";

import { useAuth } from "../../context/AuthContext";

const Register = () => {

    const navigate = useNavigate();

    const { login } = useAuth();

    const [enteredUsername, setEnteredUsername] =
        useState("");

    const [enteredPassword, setEnteredPassword] =
        useState("");

    const handleRegister = async () => {

        try {

            const data = await registerUser({
                username: enteredUsername,
                password: enteredPassword
            });

            login(data.token);

            navigate("/home");

        } catch (err) {

            console.log(err);

            alert("Registration failed");
        }
    };

    return (

        <div className="h-screen flex justify-center items-center">
            

            <div className="bg-slate-900 w-[400px] p-10 rounded-2xl shadow-xl">

                <h1 className="text-4xl font-bold text-white text-center mb-10">
                    Register
                </h1>

                <input
                    type="text"
                    placeholder="Enter username"
                    value={enteredUsername}
                    onChange={(e) =>
                        setEnteredUsername(e.target.value)
                    }
                    className="w-full px-4 py-2 border border-gray-300 rounded mb-4 focus:outline-none focus:ring-2 focus:ring-blue-500"
                />

                <input
                    type="password"
                    placeholder="Enter password"
                    value={enteredPassword}
                    onChange={(e) =>
                        setEnteredPassword(e.target.value)
                    }
                    className="w-full px-4 py-2 border border-gray-300 rounded mb-8 focus:outline-none focus:ring-2 focus:ring-blue-500"
                />

                <button
                    onClick={handleRegister}
                    className="w-full bg-blue-500 hover:bg-blue-600 text-white py-2 rounded-lg transition-all duration-300"
                >
                    Register
                </button>

                <p className="text-gray-300 text-center mt-6">

                    Already have an account?

                    <Link
                        to="/login"
                        className="text-blue-400 ml-2 hover:underline"
                    >
                        Login
                    </Link>

                </p>
            </div>
        </div>
    );
};

export default Register;
